// SemanticFailureEqOverrides carries optional per-variant hooks for SemanticFailureEqualWith.
// A hook returning handled=false falls through to the derived comparison.
type SemanticFailureEqOverrides struct {
	InvalidSemantic func(x, y InvalidSemantic) (eq, handled bool)
}

// SemanticFailureEqualWith reports structural equality of a and b under ov.
func SemanticFailureEqualWith(a, b SemanticFailure, ov SemanticFailureEqOverrides) bool {
	if a == nil || b == nil {
		return a == nil && b == nil
	}
	switch x := any(a).(type) {
	case InvalidSemantic:
		y, ok := any(b).(InvalidSemantic)
		if !ok {
			return false
		}
		if ov.InvalidSemantic != nil {
			if eq, handled := ov.InvalidSemantic(x, y); handled {
				return eq
			}
		}
		if x.Field != y.Field {
			return false
		}
		if x.Value != y.Value {
			return false
		}
		return true
	}
	return false
}

// SemanticFailureEqual reports structural equality of a and b.
func SemanticFailureEqual(a, b SemanticFailure) bool {
	return SemanticFailureEqualWith(a, b, SemanticFailureEqOverrides{})
}

func CallResolutionOf(c Call) result.Result[CallResolution, SemanticFailure] {
	switch c.Kind {
	case "internal":
		ref := ParseSymbolRef(c.Ref)
		return result.Map(result.MapError(ref, func(_ IdentityFailure) SemanticFailure { return InvalidSemantic{Field: "call ref", Value: c.Ref} }), func(r SymbolRef) CallResolution { return CallInternal{Ref: r} })
	case "external":
		if c.Ref != "" {
			return result.Err[CallResolution, SemanticFailure]{Err: InvalidSemantic{Field: "external call ref", Value: c.Ref}}
		}
		return result.Ok[CallResolution, SemanticFailure]{Value: CallExternal{}}
	case "builtin":
		if c.Ref != "" {
			return result.Err[CallResolution, SemanticFailure]{Err: InvalidSemantic{Field: "builtin call ref", Value: c.Ref}}
		}
		return result.Ok[CallResolution, SemanticFailure]{Value: CallBuiltin{}}
	case "dynamic":
		if c.Ref != "" {
			return result.Err[CallResolution, SemanticFailure]{Err: InvalidSemantic{Field: "dynamic call ref", Value: c.Ref}}
		}
		return result.Ok[CallResolution, SemanticFailure]{Value: CallDynamic{}}
	case "unresolved":
		if c.Ref != "" {
			return result.Err[CallResolution, SemanticFailure]{Err: InvalidSemantic{Field: "unresolved call ref", Value: c.Ref}}
		}
		return result.Ok[CallResolution, SemanticFailure]{Value: CallUnresolved{}}
	default:
		return result.Err[CallResolution, SemanticFailure]{Err: InvalidSemantic{Field: "call kind", Value: c.Kind}}
	}
}

// InternalCallRef is the exhaustive projection used by graph consumers.
func InternalCallRef(c Call) (string, bool) {
	resolution, failure := result.Unpack(CallResolutionOf(c))
	if failure != nil {
		return "", false
	}
	switch __gp_m0 := any(resolution).(type) {
	case CallInternal:
		ref := __gp_m0.Ref
		return SymbolRefString(ref), true
	case CallExternal, CallBuiltin, CallDynamic, CallUnresolved:
		return "", false
	default:
		panic("goplus: impossible enum value in match")
	}
}

func EvidenceOf(raw []*string) []TypeEvidence {
	out := make([]TypeEvidence, len(raw))
	for i, value := range raw {
		if value == nil {
			out[i] = EvidenceUnknown{}
		} else {
			out[i] = EvidenceStated{TypeName: *value}
		}
	}
	return out
}

// CallSetCanonical makes deterministic call normalization a law-tested
// standard-library Canonical instance rather than a sorting convention.
//
//goplus:instance CallSetCanonical "goforge.dev/goplus/std/canonical".Canonical[[]Call]
var CallSetCanonical = func() canonical.Canonical[[]Call] {
	w := &canonical.Canonical[[]Call]{
		Normalize:  func(value []Call) []Call { return DedupeCalls(value) },
		Equivalent: func(a, b []Call) bool { return reflect.DeepEqual(DedupeCalls(a), DedupeCalls(b)) },
	}
	return *w
}()

type OverloadCandidate struct {
	Target   SymbolRef
	Params   []string
	Variadic bool
}

func ResolveOverload(candidates []OverloadCandidate, arity Arity, evidence []TypeEvidence) OverloadResolution {
	var matches []SymbolRef
	for _, candidate := range candidates {
		n := int(arity)
		if (!candidate.Variadic && len(candidate.Params) != n) || (candidate.Variadic && n < len(candidate.Params)-1) {
			continue
		}
		compatible := true
		for i, ev := range evidence {
			paramIndex := i
			if paramIndex >= len(candidate.Params) {
				if candidate.Variadic && len(candidate.Params) > 0 {
					paramIndex = len(candidate.Params) - 1
				} else {
					compatible = false
					break
				}
			}
			switch __gp_m1 := any(ev).(type) {
			case EvidenceUnknown:
			case EvidenceStated:
				stated := __gp_m1.TypeName
				if stated != candidate.Params[paramIndex] {
					compatible = false
				}
			default:
				panic("goplus: impossible enum value in match")
			}
			if !compatible {
				break
			}
		}
		if compatible {
			matches = append(matches, candidate.Target)
		}
	}
	if len(matches) == 0 {
		return ResolutionImpossible{}
	}
	if len(matches) == 1 {
		return ResolutionExact{Target: matches[0]}
	}
	return ResolutionAmbiguous{Candidates: matches}
}

