func BoundOf(value string) result.Result[Bound, SemanticFailure] {
	if value == "O(1)" {
		return result.Ok[Bound, SemanticFailure]{Value: ConstantBound{}}
	}
	if value == "O(n)" {
		return result.Ok[Bound, SemanticFailure]{Value: LinearBound{}}
	}
	if strings.HasPrefix(value, "O(n^") && strings.HasSuffix(value, ")") {
		degree, err := strconv.Atoi(value[4 : len(value)-1])
		if err == nil && degree > 1 {
			return result.Ok[Bound, SemanticFailure]{Value: PolynomialBound{Degree: degree}}
		}
	}
	return result.Err[Bound, SemanticFailure]{Err: InvalidSemantic{Field: "complexity bound", Value: value}}
}

func ComplexityMeaning(c Complexity) result.Result[ComplexityEstimate, SemanticFailure] {
	switch c.Method {
	case "deferred":
		return result.Ok[ComplexityEstimate, SemanticFailure]{Value: ComplexityDeferred{}}
	case "recursive":
		return result.Ok[ComplexityEstimate, SemanticFailure]{Value: ComplexityRecursive{}}
	case "loop-nesting":
		if c.Time == nil || c.Space == nil {
			return result.Err[ComplexityEstimate, SemanticFailure]{Err: InvalidSemantic{Field: "complexity", Value: "missing bound"}}
		}
		time, tf := result.Unpack(BoundOf(*c.Time))
		if tf != nil {
			return result.Err[ComplexityEstimate, SemanticFailure]{Err: tf}
		}
		space, sf := result.Unpack(BoundOf(*c.Space))
		if sf != nil {
			return result.Err[ComplexityEstimate, SemanticFailure]{Err: sf}
		}
		return result.Ok[ComplexityEstimate, SemanticFailure]{Value: ComplexityLoopNesting{Time: time, Space: space}}
	default:
		return result.Err[ComplexityEstimate, SemanticFailure]{Err: InvalidSemantic{Field: "complexity method", Value: c.Method}}
	}
}

func SemanticSymbolOf(symbol Symbol) result.Result[SemanticSymbol, SemanticFailure] {
	id, idFailure := result.Unpack(NewSymbolID(symbol.ID))
	if idFailure != nil {
		return result.Err[SemanticSymbol, SemanticFailure]{Err: InvalidSemantic{Field: "symbol id", Value: symbol.ID}}
	}
	kind, kindFailure := result.Unpack(SymbolKindOf(symbol.Kind))
	if kindFailure != nil {
		return result.Err[SemanticSymbol, SemanticFailure]{Err: kindFailure}
	}
	visibility, visibilityFailure := result.Unpack(VisibilityOf(symbol.Visibility))
	if visibilityFailure != nil {
		return result.Err[SemanticSymbol, SemanticFailure]{Err: visibilityFailure}
	}
	idiom, idiomFailure := result.Unpack(VisibilityIdiomOf(symbol.VisibilityIdiom))
	if idiomFailure != nil {
		return result.Err[SemanticSymbol, SemanticFailure]{Err: idiomFailure}
	}
	file, fileFailure := result.Unpack(NewRelativeSourcePath(symbol.Location.File))
	if fileFailure != nil {
		return result.Err[SemanticSymbol, SemanticFailure]{Err: InvalidSemantic{Field: "source path", Value: symbol.Location.File}}
	}
	line, lineFailure := result.Unpack(PositiveSourceLine(symbol.Location.Line))
	if lineFailure != nil {
		return result.Err[SemanticSymbol, SemanticFailure]{Err: InvalidSemantic{Field: "source line", Value: strconv.Itoa(symbol.Location.Line)}}
	}
	column, columnFailure := result.Unpack(PositiveSourceColumn(symbol.Location.Col))
	if columnFailure != nil {
		return result.Err[SemanticSymbol, SemanticFailure]{Err: InvalidSemantic{Field: "source column", Value: strconv.Itoa(symbol.Location.Col)}}
	}
	documentation, docFailure := result.Unpack(DocumentationFormatOf(symbol.Doc.Format))
	if docFailure != nil {
		return result.Err[SemanticSymbol, SemanticFailure]{Err: docFailure}
	}
	complexity, complexityFailure := result.Unpack(ComplexityMeaning(symbol.Complexity))
	if complexityFailure != nil {
		return result.Err[SemanticSymbol, SemanticFailure]{Err: complexityFailure}
	}
	var invocation InvocationMeaning = NotInvokable{}
	if symbol.Invocation != nil {
		invocationKind, invocationFailure := result.Unpack(InvocationKindOf(symbol.Invocation.Kind))
		if invocationFailure != nil {
			return result.Err[SemanticSymbol, SemanticFailure]{Err: invocationFailure}
		}
		invocation = Invokable{Kind: invocationKind, How: symbol.Invocation.How}
	}
	concerns := make([]ConcernKind, len(symbol.Concerns))
	for i, raw := range symbol.Concerns {
		concern, failure := result.Unpack(ConcernKindOf(raw))
		if failure != nil {
			return result.Err[SemanticSymbol, SemanticFailure]{Err: failure}
		}
		concerns[i] = concern
	}
	calls := make([]SemanticCall, len(symbol.Calls))
	for i, raw := range symbol.Calls {
		resolution, failure := result.Unpack(CallResolutionOf(raw))
		if failure != nil {
			return result.Err[SemanticSymbol, SemanticFailure]{Err: failure}
		}
		count, countFailure := result.Unpack(PositiveCallCount(raw.Count))
		if countFailure != nil {
			return result.Err[SemanticSymbol, SemanticFailure]{Err: InvalidSemantic{Field: "call count", Value: strconv.Itoa(raw.Count)}}
		}
		var arity *Arity
		if raw.Arity != nil {
			value, arityFailure := result.Unpack(NonnegativeArity(*raw.Arity))
			if arityFailure != nil {
				return result.Err[SemanticSymbol, SemanticFailure]{Err: InvalidSemantic{Field: "arity", Value: strconv.Itoa(*raw.Arity)}}
			}
			arity = &value
		}
		calls[i] = SemanticCall{Target: raw.Target, Resolution: resolution, Arity: arity, Evidence: EvidenceOf(raw.ArgTypes), Count: count}
	}
	return result.Ok[SemanticSymbol, SemanticFailure]{Value: SemanticSymbol{
		ID: id, Kind: kind, Visibility: visibility, VisibilityIdiom: idiom,
		File: file, Line: line, Column: column, Documentation: documentation,
		Invocation: invocation, Complexity: complexity, Concerns: concerns, Calls: calls,
	}}
}

func SemanticPackageOf(pkg Package) result.Result[SemanticPackage, SemanticFailure] {
	id, idFailure := result.Unpack(NewPackageID(pkg.ID))
	if idFailure != nil {
		return result.Err[SemanticPackage, SemanticFailure]{Err: InvalidSemantic{Field: "package id", Value: pkg.ID}}
	}
	language, languageFailure := result.Unpack(LanguageOf(pkg.Language))
	if languageFailure != nil {
		return result.Err[SemanticPackage, SemanticFailure]{Err: languageFailure}
	}
	symbols := make([]SemanticSymbol, len(pkg.Symbols))
	for i, raw := range pkg.Symbols {
		symbol, failure := result.Unpack(SemanticSymbolOf(raw))
		if failure != nil {
			return result.Err[SemanticPackage, SemanticFailure]{Err: failure}
		}
		symbols[i] = symbol
	}
	return result.Ok[SemanticPackage, SemanticFailure]{Value: SemanticPackage{ID: id, Language: language, Symbols: symbols}}
}
